# vault-policy-deploy-prod.hcl
# Allow the CI deploy job to read production secrets but not write them.

# Read LLM API keys
path "secret/data/prod/anthropic" {
  capabilities = ["read"]
}
path "secret/data/prod/openai" {
  capabilities = ["read"]
}

# Read database connection strings
path "secret/data/prod/postgres" {
  capabilities = ["read"]
}

# Explicitly deny access to rotation admin keys
path "secret/data/prod/anthropic_admin" {
  capabilities = ["deny"]
}

# Allow token self-renewal (to handle long-running jobs)
path "auth/token/renew-self" {
  capabilities = ["update"]
}
